package org.acme.orders.messaging;

import org.eclipse.microprofile.reactive.messaging.Incoming;
import jakarta.enterprise.context.ApplicationScoped;

@ApplicationScoped
class BadOrderConsumer {
    @Incoming("orders-in")
    void onMessage(String payload) {
        // Bad: manual parsing and side effects with no contract typing, blocking the event loop
    }
}

package org.acme.orders.messaging;

import org.eclipse.microprofile.reactive.messaging.Incoming;
import org.eclipse.microprofile.reactive.messaging.Message;
import java.util.concurrent.CompletionStage;
import jakarta.enterprise.context.ApplicationScoped;

@ApplicationScoped
class BadOrderConsumer {
    @Incoming("orders-in")
    public CompletionStage<Void> onMessage(Message<OrderCreatedEvent> message) {
        try {
            // process(message.getPayload());
            return message.ack();
        } catch (Exception e) {
            return message.ack(); // Bad: acknowledges failed records, losing data
        }
    }
}

